      "cssContent": ".comp-16-button-container{position: relative;overflow: hidden} .comp-16-button-container .main{display: flex;flex-direction: column;gap: 0.5em} .comp-16-button-container .up{display: flex;flex-direction: row;gap: 0.5em} .comp-16-button-container .down{display: flex;flex-direction: row;gap: 0.5em} .comp-16-button-container .card1{width: 90px;height: 90px;outline: none;border: none;background: white;border-radius: 90px 5px 5px 5px;box-shadow: rgba(50,50,93,0.25) 0px 2px 5px -1px,rgba(0,0,0,0.3) 0px 1px 3px -1px;transition: .2s ease-in-out} .comp-16-button-container .instagram{margin-top: 1.5em;margin-left: 1.2em;fill: #cc39a4} .comp-16-button-container .card2{width: 90px;height: 90px;outline: none;border: none;background: white;border-radius: 5px 90px 5px 5px;box-shadow: rgba(50,50,93,0.25) 0px 2px 5px -1px,rgba(0,0,0,0.3) 0px 1px 3px -1px;transition: .2s ease-in-out} .comp-16-button-container .twitter{margin-top: 1.5em;margin-left: -.9em;fill: #03A9F4} .comp-16-button-container .card3{width: 90px;height: 90px;outline: none;border: none;background: white;border-radius: 5px 5px 5px 90px;box-shadow: rgba(50,50,93,0.25) 0px 2px 5px -1px,rgba(0,0,0,0.3) 0px 1px 3px -1px;transition: .2s ease-in-out} .comp-16-button-container .github{margin-top: -.6em;margin-left: 1.2em} .comp-16-button-container .card4{width: 90px;height: 90px;outline: none;border: none;background: white;border-radius: 5px 5px 90px 5px;box-shadow: rgba(50,50,93,0.25) 0px 2px 5px -1px,rgba(0,0,0,0.3) 0px 1px 3px -1px;transition: .2s ease-in-out} .comp-16-button-container .discord{margin-top: -.9em;margin-left: -1.2em;fill: #8c9eff} .comp-16-button-container .card1:hover{cursor: pointer;scale: 1.1;background-color: #cc39a4} .comp-16-button-container .card1:hover .instagram{fill: white} .comp-16-button-container .card2:hover{cursor: pointer;scale: 1.1;background-color: #03A9F4} .comp-16-button-container .card2:hover .twitter{fill: white} .comp-16-button-container .card3:hover{cursor: pointer;scale: 1.1;background-color: black} .comp-16-button-container .card3:hover .github{fill: white} .comp-16-button-container .card4:hover{cursor: pointer;scale: 1.1;background-color: #8c9eff} .comp-16-button-container .card4:hover .discord{fill: white}"
