      "htmlContent": "<div class=\"comp-35-button-container\"><button class=\"ui-btn\"><span> Button </span></button></div>",
      "cssContent": ".comp-35-button-container{position: relative;overflow: hidden} .comp-35-button-container .ui-btn{--btn-default-bg: rgb(41,41,41);--btn-padding: 15px 20px;--btn-hover-bg: rgb(51,51,51);--btn-transition: .3s;--btn-letter-spacing: .1rem;--btn-animation-duration: 1.2s;--btn-shadow-color: rgba(0,0,0,0.137);--btn-shadow: 0 2px 10px 0 var(--btn-shadow-color);--hover-btn-color: #FAC921;--default-btn-color: #fff;--font-size: 16px;--font-weight: 600;--font-family: Menlo,Roboto Mono,monospace} .comp-35-button-container .ui-btn{box-sizing: border-box;padding: var(--btn-padding);display: flex;align-items: center;justify-content: center;color: var(--default-btn-color);font: var(--font-weight) var(--font-size) var(--font-family);background: var(--btn-default-bg);border: none;cursor: pointer;transition: var(--btn-transition);overflow: hidden;box-shadow: var(--btn-shadow)} .comp-35-button-container .ui-btn span{letter-spacing: var(--btn-letter-spacing);transition: var(--btn-transition);box-sizing: border-box;position: relative;background: inherit} .comp-35-button-container .ui-btn span::before{box-sizing: border-box;position: absolute;content: \"\";background: inherit} .comp-35-button-container .ui-btn:hover,.ui-btn:focus{background: var(--btn-hover-bg)} .comp-35-button-container .ui-btn:hover span,.ui-btn:focus span{color: var(--hover-btn-color)} .comp-35-button-container .ui-btn:hover span::before,.ui-btn:focus span::before{animation: chitchat linear both var(--btn-animation-duration)} @keyframes chitchat{.comp-35-button-container 0%{content: \"#\"} .comp-35-button-container 5%{content: \".\"} .comp-35-button-container 10%{.comp-35-button-container content: \"^{\"} .comp-35-button-container 15%{content: \"-!\"} .comp-35-button-container 20%{content: \"#$_\"} .comp-35-button-container 25%{content: \"№:0\"} .comp-35-button-container 30%{.comp-35-button-container content: \"#{+.\"} .comp-35-button-container 35%{content: \"@}-?\"} 40%{content: \"?{4@%\"} 45%{content: \"=.,^!\"} 50%{content: \"?2@%\"} 55%{content: \"\\;1}]\"} .comp-35-button-container 60%{.comp-35-button-container content: \"?{%:%\";right: 0} .comp-35-button-container 65%{.comp-35-button-container content: \"|{f[4\";right: 0} .comp-35-button-container 70%{.comp-35-button-container content: \"{4%0%\";right: 0} .comp-35-button-container 75%{content: \"'1_0<\";right: 0} .comp-35-button-container 80%{.comp-35-button-container content: \"{0%\";right: 0} .comp-35-button-container 85%{content: \"]>'\";right: 0} .comp-35-button-container 90%{content: \"4\";right: 0} .comp-35-button-container 95%{content: \"2\";right: 0} .comp-35-button-container 100%{content: \"\";right: 0} }"
