      "htmlContent": "<div class=\"comp-43-button-container\"><div data-tooltip=\"Price:-$20\" class=\"button\"><div class=\"button-wrapper\"><div class=\"text\">Buy Now</div><span class=\"icon\"><svg viewBox=\"0 0 16 16\" class=\"bi bi-cart2\" fill=\"currentColor\" height=\"16\" width=\"16\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M0 2.5A.5.5 0 0 1 .5 2H2a.5.5 0 0 1 .485.379L2.89 4H14.5a.5.5 0 0 1 .485.621l-1.5 6A.5.5 0 0 1 13 11H4a.5.5 0 0 1-.485-.379L1.61 3H.5a.5.5 0 0 1-.5-.5zM3.14 5l1.25 5h8.22l1.25-5H3.14zM5 13a1 1 0 1 0 0 2 1 1 0 0 0 0-2zm-2 1a2 2 0 1 1 4 0 2 2 0 0 1-4 0zm9-1a1 1 0 1 0 0 2 1 1 0 0 0 0-2zm-2 1a2 2 0 1 1 4 0 2 2 0 0 1-4 0z\"></path></svg></span></div></div></div>",
      "cssContent": ".comp-43-button-container{position: relative;overflow: hidden} .comp-43-button-container .button{--width: 100px;--height: 35px;--tooltip-height: 35px;--tooltip-width: 90px;--gap-between-tooltip-to-button: 18px;--button-color: #222;--tooltip-color: #fff;width: var(--width);height: var(--height);background: var(--button-color);position: relative;text-align: center;border-radius: 0.45em;font-family: \"Arial\";transition: background 0.3s} .comp-43-button-container .button::before{position: absolute;content: attr(data-tooltip);width: var(--tooltip-width);height: var(--tooltip-height);background-color: #555;font-size: 0.9rem;color: #fff;border-radius: .25em;line-height: var(--tooltip-height);bottom: calc(var(--height) + var(--gap-between-tooltip-to-button) + 10px);left: calc(50% - var(--tooltip-width) / 2)} .comp-43-button-container .button::after{position: absolute;content: '';width: 0;height: 0;border: 10px solid transparent;border-top-color: #555;left: calc(50% - 10px);bottom: calc(100% + var(--gap-between-tooltip-to-button) - 10px)} .comp-43-button-container .button::after,.button::before{opacity: 0;visibility: hidden;transition: all 0.5s} .comp-43-button-container .text{display: flex;align-items: center;justify-content: center} .comp-43-button-container .button-wrapper,.text,.icon{overflow: hidden;position: absolute;width: 100%;height: 100%;left: 0;color: #fff} .comp-43-button-container .text{top: 0 } .comp-43-button-container .text,.icon{transition: top 0.5s} .comp-43-button-container .icon{color: #fff;top: 100%;display: flex;align-items: center;justify-content: center} .comp-43-button-container .icon svg{width: 24px;height: 24px} .comp-43-button-container .button:hover{background: #222} .comp-43-button-container .button:hover .text{top: 0} .comp-43-button-container .button:hover .icon{top: 0} .comp-43-button-container .button:hover:before,.button:hover:after{opacity: 1;visibility: visible} .comp-43-button-container .button:hover:after{bottom: calc(var(--height) + var(--gap-between-tooltip-to-button) - 20px)} .comp-43-button-container .button:hover:before{bottom: calc(var(--height) + var(--gap-between-tooltip-to-button))}"
