      "cssContent": ".comp-8-button-container{position: relative;overflow: hidden} .comp-8-button-container #heart{display: none} .comp-8-button-container .like-button{position: relative;cursor: pointer;display: flex;height: 48px;width: 136px;border-radius: 16px;border: none;background-color: #1d1d1d;overflow: hidden;box-shadow: inset -2px -2px 5px rgba(255,255,255,0.2),inset 2px 2px 5px rgba(0,0,0,0.1),4px 4px 10px rgba(0,0,0,0.4),-2px -2px 8px rgba(255,255,255,0.1)} .comp-8-button-container .like{width: 70%;height: 100%;display: flex;cursor: pointer;align-items: center;justify-content: space-evenly} .comp-8-button-container .like-icon{fill: #505050;height: 28px;width: 28px} .comp-8-button-container .like-text{color: #fcfcfc;font-size: 16px;font-family: \"Segoe UI\",Tahoma,Geneva,Verdana,sans-serif} .comp-8-button-container .like-count{position: absolute;right: 0;width: 30%;height: 100%;display: flex;justify-content: center;align-items: center;color: #717070;font-size: 16px;border-left: 2px solid #4e4e4e;transition: all 0.5s ease-out} .comp-8-button-container .like-count.two{transform: translateY(40px)} .comp-8-button-container .on:checked ~ .like .like-icon{fill: #fc4e4e;animation: enlarge 0.2s ease-out 1;transition: all 0.2s ease-out} .comp-8-button-container .on:checked ~ .like-count.two{transform: translateX(0);color: #fcfcfc} .comp-8-button-container .on:checked ~ .like-count.one{transform: translateY(-40px)} @keyframes enlarge{0%{transform: scale(0.5)} 100%{transform: scale(1.2)} }"
