      "cssContent": ".comp-13-cards-container{position: relative;overflow: hidden} .comp-13-cards-container .card{width: 195px;height: 285px;background: #313131;border-radius: 20px;;display: flex;flex-direction: column;align-items: center;justify-content: center;color: white;transition: 0.2s ease-in-out} .comp-13-cards-container .img{height: 30%;position: absolute;transition: 0.2s ease-in-out;z-index: 1} .comp-13-cards-container .textBox{opacity: 0;display: flex;flex-direction: column;align-items: center;justify-content: center;gap: 15px;transition: 0.2s ease-in-out;z-index: 2} .comp-13-cards-container .textBox > .text{font-weight: bold} .comp-13-cards-container .textBox > .head{font-size: 20px} .comp-13-cards-container .textBox > .price{font-size: 17px} .comp-13-cards-container .textBox > span{font-size: 12px;color: lightgrey} .comp-13-cards-container .card:hover > .textBox{opacity: 1} .comp-13-cards-container .card:hover > .img{height: 65%;filter: blur(7px);animation: anim 3s infinite} @keyframes anim{0%{transform: translateY(0)} 50%{transform: translateY(-20px)} 100%{transform: translateY(0)} } .comp-13-cards-container .card:hover{transform: scale(1.04) rotate(-1deg)}"
