      "cssContent": ".comp-17-cards-container{position: relative;overflow: hidden} .comp-17-cards-container .container{position: relative;display: flex;justify-content: center;align-items: center} .comp-17-cards-container .container .glass{position: relative;width: 180px;height: 200px;background: linear-gradient(#fff2,transparent);border: 1px solid rgba(255,255,255,0.1);box-shadow: 0 25px 25px rgba(0,0,0,0.25);display: flex;justify-content: center;align-items: center;transition: 0.5s;border-radius: 10px;margin: 0 -45px;backdrop-filter: blur(10px);transform: rotate(calc(var(--r) * 1deg))} .comp-17-cards-container .container:hover .glass{transform: rotate(0deg);margin: 0 10px} .comp-17-cards-container .container .glass::before{content: attr(data-text);position: absolute;bottom: 0;width: 100%;height: 40px;background: rgba(255,255,255,0.05);display: flex;justify-content: center;align-items: center;color: #fff} .comp-17-cards-container .container .glass svg{font-size: 2.5em;fill: #fff}"
