      "cssContent": ".comp-9-cards-container{position: relative;overflow: hidden} .comp-9-cards-container .card{width: 300px;height: 200px;background: #243137;position: relative;display: grid;place-content: center;border-radius: 10px;overflow: hidden;transition: all 0.5s ease-in-out} .comp-9-cards-container #logo-main,#logo-second{height: 100%} .comp-9-cards-container #logo-main{fill: #bd9f67} .comp-9-cards-container #logo-second{padding-bottom: 10px;fill: none;stroke: #bd9f67;stroke-width: 1px} .comp-9-cards-container .border{position: absolute;inset: 0px;border: 2px solid #bd9f67;opacity: 0;transform: rotate(10deg);transition: all 0.5s ease-in-out} .comp-9-cards-container .bottom-text{position: absolute;left: 50%;bottom: 13px;transform: translateX(-50%);font-size: 6px;text-transform: uppercase;padding: 0px 5px 0px 8px;color: #bd9f67;background: #243137;opacity: 0;letter-spacing: 7px;transition: all 0.5s ease-in-out} .comp-9-cards-container .content{transition: all 0.5s ease-in-out} .comp-9-cards-container .content .logo{height: 35px;position: relative;width: 33px;overflow: hidden;transition: all 1s ease-in-out} .comp-9-cards-container .content .logo .logo1{height: 33px;position: absolute;left: 0} .comp-9-cards-container .content .logo .logo2{height: 33px;position: absolute;left: 33px} .comp-9-cards-container .content .logo .trail{position: absolute;right: 0;height: 100%;width: 100%;opacity: 0} .comp-9-cards-container .content .logo-bottom-text{position: absolute;left: 50%;top: 50%;transform: translate(-50%,-50%);margin-top: 30px;color: #bd9f67;padding-left: 8px;font-size: 11px;opacity: 0;letter-spacing: none;transition: all 0.5s ease-in-out 0.5s} .comp-9-cards-container .card:hover{border-radius: 0;transform: scale(1.1)} .comp-9-cards-container .card:hover .logo{width: 134px;animation: opacity 1s ease-in-out} .comp-9-cards-container .card:hover .border{inset: 15px;opacity: 1;transform: rotate(0)} .comp-9-cards-container .card:hover .bottom-text{letter-spacing: 3px;opacity: 1;transform: translateX(-50%)} .comp-9-cards-container .card:hover .content .logo-bottom-text{opacity: 1;letter-spacing: 9.5px} .comp-9-cards-container .card:hover .trail{animation: trail 1s ease-in-out} @keyframes opacity{0%{border-right: 1px solid transparent} 10%{border-right: 1px solid #bd9f67} 80%{border-right: 1px solid #bd9f67} 100%{border-right: 1px solid transparent} } @keyframes trail{0%{background: linear-gradient(90deg,rgba(189,159,103,0) 90%,rgb(189,159,103) 100%);opacity: 0} 30%{background: linear-gradient(90deg,rgba(189,159,103,0) 70%,rgb(189,159,103) 100%);opacity: 1} 70%{background: linear-gradient(90deg,rgba(189,159,103,0) 70%,rgb(189,159,103) 100%);opacity: 1} 95%{background: linear-gradient(90deg,rgba(189,159,103,0) 90%,rgb(189,159,103) 100%);opacity: 0} }"
