      "cssContent": ".comp-43-checkbox-container{position: relative;overflow: hidden} .comp-43-checkbox-container .cbx{-webkit-perspective: 20;perspective: 20;position: absolute;top: 50%;left: 50%;margin: -12px;border: 2px solid #e8e8eb;background: #e8e8eb;border-radius: 4px;transform: translate3d(0,0,0);cursor: pointer;transition: all 0.3s ease} .comp-43-checkbox-container .cbx:hover{border-color: #0b76ef} .comp-43-checkbox-container .flip{display: block;transition: all 0.4s ease;transform-style: preserve-3d;position: relative;width: 20px;height: 20px} .comp-43-checkbox-container #cbx{display: none} .comp-43-checkbox-container #cbx:checked ~ .cbx{border-color: #07f} .comp-43-checkbox-container #cbx:checked ~ .flip{transform: rotateY(180deg)} .front,.comp-43-checkbox-container .back{backface-visibility: hidden;position: absolute;top: 0;left: 0;width: 20px;height: 20px;border-radius: 2px} .comp-43-checkbox-container .front{background: #fff;z-index: 1} .comp-43-checkbox-container .back{transform: rotateY(180deg);background: #0b76ef;text-align: center;color: #fff;line-height: 20px;box-shadow: 0 0 0 1px #0b76ef} .comp-43-checkbox-container .back svg{margin-top: 3px;fill: none} .comp-43-checkbox-container .back svg path{stroke: #fff;stroke-width: 2.5;stroke-linecap: round;stroke-linejoin: round}"
